import { v4 as uuidv4 } from "uuid";
import RepositoryDefaults from "./RepositoryDefaults";
import RepositoryUrls from "./RepositoryUrls";
import { FetchError } from "./RepositoryErrors";
import React from "react";
import "./Repository.css"; // importiamo il CSS della card

export default class Repository {
  constructor(data = {}) {
    this.id = data.id || uuidv4();
    this.name = data.name || "unknown";
    this.fullName = data.full_name || "";
    this.description = data.description || "";
    this.url = data.html_url || "";
    this.cloneUrl = data.clone_url || "";
    this.owner = data.owner?.login || "unknown";
    this.ownerUrl = data.owner?.html_url || "";
    this.ownerAvatar = data.owner?.avatar_url || RepositoryDefaults.AVATAR;
    this.license = data.license?.name || RepositoryDefaults.LICENSE;
    this.visibility = data.private ? "private" : RepositoryDefaults.VISIBILITY;
    this.status = data.archived ? "archived" : data.fork ? "fork" : RepositoryDefaults.STATUS;

    this.creationDate = data.created_at ? new Date(data.created_at) : new Date();
    this.lastUpdate = data.updated_at ? new Date(data.updated_at) : new Date();
    this.stars = data.stargazers_count || 0;
    this.forks = data.forks_count || 0;
    this.issuesUrl = `${this.url}/issues`;
    this.documentationLink = data.has_wiki ? `${this.url}/wiki` : null;

    this.liveDemoLink = data.liveDemoLink || RepositoryDefaults.LIVE_DEMO;
    this.screenshots = data.screenshots || RepositoryDefaults.SCREENSHOTS;

    this.languages = [];
    this.readme = null;
    this.readmeRawUrl = "";
    this.contributorsUrl = data.contributors_url || "";
    this.contributors = [];

    this.coverImage = data.coverImage || RepositoryDefaults.COVER_IMAGE;
  }

  copyGitClone() {
    navigator.clipboard.writeText(`git clone ${this.cloneUrl}`);
    alert(`Git clone URL copied:\n${this.cloneUrl}`);
  }

  // metodo per rendere la card della repository
  renderCard() {
    return (
      <div key={this.id} className="repo-card">
        <img src={this.coverImage} alt={`${this.name} cover`} className="repo-cover" />

        <div className="repo-body">
          <div className="repo-header">
            <img src={this.ownerAvatar} alt={this.owner} className="repo-owner-avatar" />
            <a href={this.url} target="_blank" rel="noopener noreferrer" className="repo-name">
              {this.name}
            </a>
          </div>

          {this.description && <p className="repo-description">{this.description}</p>}

          {this.languages.length > 0 && (
            <div className="repo-languages">
              {this.languages.map((lang) => (
                <span key={lang} className="repo-language">{lang}</span>
              ))}
            </div>
          )}

          <div className="repo-actions">
            <button onClick={() => this.copyGitClone()}>Copy git clone</button>
            {this.documentationLink && (
              <a href={this.documentationLink} target="_blank" rel="noopener noreferrer">
                Wiki / Docs
              </a>
            )}
          </div>
        </div>
      </div>
    );
  }
}
